Here is an example code for a Discord bot using Discord.js v14, which includes a ban command:

```
const Discord = require('discord.js');
const client = new Discord.Client();

client.on('ready', () => {
  console.log('Bot is ready!');
});

client.on('message', message => {
  if (message.content === 'ban <user> <reason>') {
    const target = message.mentions.users.first();
    const reason = message.content.slice(6).trim();

    if (!target) {
      return message.channel.send('Couldn\'t find a valid user to ban!');
    }

    const guild = message.guild;
    guild.members.ban(target, { reason });
    message.channel.send(`Banned ${target} (${target.id}) for ${reason}!`);
  }
});

client.login('YOUR_TOKEN_HERE');
```

To use this code, you will need to replace 'YOUR_TOKEN_HERE' with your Discord bot token. You can create a Discord bot and get a token by following the instructions on the Discord Developer Portal.

