#include <iostream>
#include <sstream>
#include <string>

std::string markdownToHtml(const std::string& markdown)
{
    std::stringstream ss;
    ss << "<html>" << std::endl;
    ss << "<head>" << std::endl;
    ss << "<title>Untitled</title>" << std::endl;
    ss << "</head>" << std::endl;
    ss << "<body>" << std::endl;

    std::string html = "";
    std::string markdown_text;

    std::string markdown_content = markdown;
    size_t start_pos = 0;
    size_t end_pos = 0;

    while ((end_pos = markdown_content.find("> ", start_pos))!= std::string::npos) {
        html += markdown_content.substr(start_pos, end_pos - start_pos + 2) + "<br>";
        start_pos = end_pos + 2;
    }

    html += markdown_content.substr(start_pos);

    std::stringstream out;
    out << "<p>" << html << "</p>";
    out << "</body>" << std::endl;
    out << "</html>";

    return out.str();
}
```

