extends KinematicBody2D

func _physics_process(delta):
    # Get the direction the character is facing
    var direction = -self.get_global_transform().basis.z.normalized()

    # Move the character in the direction it's facing
    self.set_position(self.position + direction * self.speed * delta)

    # Check if the character has collided with anything
    if self.collision_shape.check_collision_recursive(self.global_transform.origin):
        # Stop the character from moving
        self.speed = 0

func _on_controller_pressed():
