        self.speed = 10
    if Input.is_action_pressed("move_backward"):
        self.speed = -10
    if Input.is_action_pressed("move_left"):
        self.speed = -10
    if Input.is_action_pressed("move_right"):
        self.speed = 10

func _input(event):
    # Use the input event to update the character's movement direction
    if Input.is_action_pressed("move_forward") or Input.is_action_pressed("move_backward"):
        direction = Input.get_action_vector("move_forward") + Input.get_action_vector("move_backward")
        direction = direction.normalized()
        self.set_global_transform(self.transform.basis.xform(direction))
    if Input.is_action_pressed("move_left") or Input.is_action_pressed("move_right"):
        direction = Input.get_action_vector("move_left") + Input.get_action_vector("move_right")
